import java.time.*;
import java.time.format.*;
import java.time.temporal.*;

public class DateTimeDemo {
    public static void main(String[] args) {
        // ── LocalDate ────────────────────────────────
        LocalDate today    = LocalDate.now();
        LocalDate dob      = LocalDate.of(1995, Month.JUNE, 15);
        LocalDate nextYear = today.plusYears(1);

        Period age = Period.between(dob, today);
        System.out.println("Age: " + age.getYears() + " years, " + age.getMonths() + " months");

        // ── LocalDateTime ────────────────────────────
        LocalDateTime now   = LocalDateTime.now();
        LocalDateTime later = now.plusHours(2).plusMinutes(30);
        Duration gap        = Duration.between(now, later);
        System.out.println("Gap: " + gap.toMinutes() + " minutes");

        // ── Formatting & Parsing ─────────────────────
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("dd-MMM-yyyy HH:mm");
        System.out.println(now.format(fmt));
        LocalDateTime parsed = LocalDateTime.parse("25-Dec-2024 09:30", fmt);
        System.out.println(parsed.getDayOfWeek()); // WEDNESDAY

        // ── ZonedDateTime ────────────────────────────
        ZonedDateTime ist = ZonedDateTime.now(ZoneId.of("Asia/Kolkata"));
        ZonedDateTime utc = ist.withZoneSameInstant(ZoneOffset.UTC);
        System.out.println("IST: " + ist.toLocalTime());
        System.out.println("UTC: " + utc.toLocalTime());

        // ── Instant ─────────────────────────────────
        Instant start = Instant.now();
        long   epochMs = start.toEpochMilli();
        System.out.println("Epoch ms: " + epochMs);

        // ── ChronoUnit ───────────────────────────────
        long daysUntilXmas = ChronoUnit.DAYS.between(today, LocalDate.of(today.getYear(), 12, 25));
        System.out.println("Days until Xmas: " + daysUntilXmas);
    }
}

import java.time.*;
import java.time.temporal.*;
import java.util.Set;

public class BusinessDays {

    static final Set<DayOfWeek> WEEKENDS = Set.of(DayOfWeek.SATURDAY, DayOfWeek.SUNDAY);

    // Custom TemporalAdjuster: next business day
    static TemporalAdjuster nextBusinessDay() {
        return temporal -> {
            LocalDate date = LocalDate.from(temporal);
            do { date = date.plusDays(1); } while (WEEKENDS.contains(date.getDayOfWeek()));
            return date;
        };
    }

    static long businessDaysBetween(LocalDate start, LocalDate end) {
        long count = 0;
        LocalDate d = start;
        while (d.isBefore(end)) {
            if (!WEEKENDS.contains(d.getDayOfWeek())) count++;
            d = d.plusDays(1);
        }
        return count;
    }

    public static void main(String[] args) {
        LocalDate friday = LocalDate.of(2024, 12, 6); // Friday
        LocalDate next   = friday.with(nextBusinessDay());
        System.out.println("Next biz day: " + next + " (" + next.getDayOfWeek() + ")");

        // Built-in adjusters
        LocalDate today = LocalDate.of(2024, 12, 10);
        System.out.println("First of month: " + today.with(TemporalAdjusters.firstDayOfMonth()));
        System.out.println("Last of year:   " + today.with(TemporalAdjusters.lastDayOfYear()));
        System.out.println("Next Monday:    " + today.with(TemporalAdjusters.next(DayOfWeek.MONDAY)));

        LocalDate jan1 = LocalDate.of(2024, 1, 1);
        LocalDate dec31 = LocalDate.of(2024, 12, 31);
        System.out.println("Business days in 2024: " + businessDaysBetween(jan1, dec31));
    }
}

