import java.time.*;
import java.time.format.*;

public class Q2 {
    static final DateTimeFormatter FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");
    public static String istToUtc(String istDateTime) {
        LocalDateTime ldt = LocalDateTime.parse(istDateTime, FMT);
        ZonedDateTime ist = ldt.atZone(ZoneId.of("Asia/Kolkata"));
        ZonedDateTime utc = ist.withZoneSameInstant(ZoneOffset.UTC);
        return utc.toLocalDateTime().format(FMT);
    }
    public static void main(String[] args) {
        System.out.println(istToUtc("2024-06-15 14:30")); // 2024-06-15 09:00
    }
}

