import java.time.*;
import java.time.temporal.*;

public class Q3 {
    public static long daysUntilBirthday(String mmdd) {
        String[] parts = mmdd.split("-");
        int month = Integer.parseInt(parts[0]), day = Integer.parseInt(parts[1]);
        LocalDate today = LocalDate.now();
        LocalDate next = LocalDate.of(today.getYear(), month, day);
        if (next.isBefore(today)) next = next.plusYears(1);
        return ChronoUnit.DAYS.between(today, next);
    }
    public static void main(String[] args) {
        System.out.println(daysUntilBirthday("12-25"));
    }
}
